namespace {
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }
static inline uint32_t MinU32(uint32_t a, uint32_t b) { return a < b ? a : b; }
} // namespace

namespace optiling {

// Conservative per-core UB budget for AICore
static constexpr uint32_t UB_BUDGET_BYTES = 180 * 1024;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dSubtractTanhSubtractAvgPoolCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const uint32_t N  = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t Cin = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t H  = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t W  = static_cast<uint32_t>(x_shape->GetDim(3));

    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetDim(0));
    const uint32_t Kh = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t Kw = static_cast<uint32_t>(w_shape->GetDim(3));

    // Conv parameters fixed: stride=1, padding=0, dilation=1
    const uint32_t Oh = (H >= Kh) ? (H - Kh + 1) : 0;
    const uint32_t Ow = (W >= Kw) ? (W - Kw + 1) : 0;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *subtract1_value = attrs->GetAttrPointer<float>(0);
    const float *subtract2_value = attrs->GetAttrPointer<float>(1);
    const int32_t *kernel_size_pool = attrs->GetAttrPointer<int32_t>(2);
    const uint32_t ksp = static_cast<uint32_t>(*kernel_size_pool);

    // Pool parameters: kernel = stride = ksp, no padding
    const uint32_t Ph = (ksp == 0) ? 0u : (Oh / ksp);
    const uint32_t Pw = (ksp == 0) ? 0u : (Ow / ksp);

    // Bias presence
    uint32_t hasBias = 0;
    if (context->GetNumInputs() > 2 && context->GetInputShape(2) != nullptr) {
        const gert::Shape *b_shape = context->GetInputShape(2);
        if (b_shape->GetShapeSize() > 0) hasBias = 1;
    }

    // Choose tileCo based on UB budget
    uint32_t tileCo = MinU32(16u, Cout);
    uint32_t patchH = ksp + Kh - 1;
    uint32_t patchW = ksp + Kw - 1;

    auto FitsUB = [&](uint32_t tCo) -> bool {
        uint64_t wBytes   = static_cast<uint64_t>(tCo) * Cin * Kh * Kw * sizeof(float);
        uint64_t xBytes   = static_cast<uint64_t>(Cin) * patchH * patchW * sizeof(float); // tileQ=1
        uint64_t vecBytes = static_cast<uint64_t>(4u * tCo) * sizeof(float); // convVec, tmpVec, tanhVec, accVec
        uint64_t total = wBytes + xBytes + vecBytes;
        return total <= UB_BUDGET_BYTES;
    };

    while (tileCo > 1u && !FitsUB(tileCo)) {
        tileCo >>= 1u;
    }
    if (tileCo == 0u) tileCo = 1u;

    uint32_t coTiles = CeilDiv(Cout, tileCo);
    uint32_t blockDim = coTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_Cin(Cin);
    tiling.set_Cout(Cout);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_Kh(Kh);
    tiling.set_Kw(Kw);
    tiling.set_Oh(Oh);
    tiling.set_Ow(Ow);
    tiling.set_Ph(Ph);
    tiling.set_Pw(Pw);
    tiling.set_ksp(ksp);
    tiling.set_tileCo(tileCo);
    tiling.set_patchH(patchH);
    tiling.set_patchW(patchW);
    tiling.set_hasBias(hasBias);
    tiling.set_blockDim(blockDim);
    tiling.set_subtract1(*subtract1_value);
    tiling.set_subtract2(*subtract2_value);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

